INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300010000', '22222222-2222-2222-2222-222222220001', 'ما الفرق بين ممارسة عاشوراء وعيش عاشوراء؟', '• الطقس أم التحول؟\n• التأثر المؤقت أم التغيير الحقيقي؟\n• كيف تتحول الذكرى إلى وعي؟', 1);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300010001', '22222222-2222-2222-2222-222222220001', 'لماذا لا تغيّرنا المشاعر دائمًا؟', '• العاطفة المؤقتة.\n• الاعتياد الديني.\n• الشعور الزائف بالإنجاز الروحي.', 2);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300010002', '22222222-2222-2222-2222-222222220001', 'ماذا يعني أن نعيش الحسين؟', '• الحسين في القرار اليومي.\n• الإصلاح كمسؤولية.\n• الثبات على المبدأ.', 3);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300010003', '22222222-2222-2222-2222-222222220001', 'كربلاء: مدرسة موقف', '• لماذا لم تكن كربلاء مجرد عاطفة؟\n• الحب الذي تحوّل إلى تضحية.\n• كيف عاش أصحاب الحسين القضية؟', 4);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300010004', '22222222-2222-2222-2222-222222220001', 'كيف تتحول عاشوراء إلى أثر؟', '• مراجعة الذات بعد الموسم.\n• اختيار قيمة حسينية للعيش بها.\n• تحويل الوعي إلى ممارسة.', 5);
