INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300020000', '22222222-2222-2222-2222-222222220002', 'هل يمكن للمشاعر النبيلة أن تصبح خطرًا؟', '• النية الحسنة لا تكفي دائمًا.\n• الحب بلا بصيرة.\n• لماذا لا تقود المشاعر دائمًا إلى نتائج صحيحة؟', 1);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300020001', '22222222-2222-2222-2222-222222220002', 'لماذا خلق الله العاطفة؟', '• العاطفة كمحرّك وجودي.\n• البكاء في القرآن وسيرة الأنبياء.\n• هل أُريد للدمعة أن تكون محطة… أم وقودًا؟', 2);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300020002', '22222222-2222-2222-2222-222222220002', 'هل العاطفة وحدها تغيّر الإنسان؟', '• لماذا لا تكفي المشاعر وحدها؟\n• الشعور الزائف بالإنجاز الأخلاقي.\n• لماذا يتأثر بعض الناس… ثم يعود كل شيء كما كان؟', 3);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300020003', '22222222-2222-2222-2222-222222220002', 'كربلاء: الحب الذي لم يتحول إلى موقف', '• أهل الكوفة: حب بلا ثبات.\n• كيف اجتمع حب الحسين… مع خذلان الحسين؟\n• الفرق بين التأثر… والنصرة.', 4);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300020004', '22222222-2222-2222-2222-222222220002', 'ما معنى الوعي الرسالي؟', '• تحويل الحب إلى مسؤولية.\n• الثبات بدل الانفعال المؤقت.\n• أن يبقى الحسين حاضرًا في القرار اليومي.', 5);
