INSERT INTO cards (id, night_id, slug, type, title, content, status) VALUES ('77777777-7777-7777-7777-777700020000', '22222222-2222-2222-2222-222222220002', 'quote-night-2', 'quote', 'الإمام جعفر الصادق (ع)', 'العامل على غير بصيرة كالسائر على غير الطريق، لا تزيده سرعة السير إلا بُعدًا', 'published');
