INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300030000', '22222222-2222-2222-2222-222222220003', 'وهم المعرفة السريعة', '• كيف صنعت وسائل التواصل شعورًا زائفًا بالفهم؟\n• الفرق بين المعلومة والمعرفة.\n• لماذا لا يكفي “مقطع قصير” لفهم القضايا العميقة؟', 1);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300030001', '22222222-2222-2222-2222-222222220003', 'خطر أنصاف الحقائق', '• كيف يضللنا الفهم المبتور؟\n• متى تصبح نصف الحقيقة أخطر من الجهل؟\n• أثر الاجتزاء على فهم الدين والتاريخ.', 2);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300030002', '22222222-2222-2222-2222-222222220003', 'القراءة كوعي لا كمعلومات', '• لماذا نقرأ؟\n• القراءة بوصفها بناءً للفهم لا تراكمًا للمعلومات.\n• الفرق بين القراءة السطحية والقراءة الواعية.', 3);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300030003', '22222222-2222-2222-2222-222222220003', 'كربلاء وأزمة الوعي', '• هل خُذل الحسين بسبب الجهل… أم بسبب أشباه المعرفة؟\n• كيف يصنع الوعي موقفًا؟\n• لماذا لا تكفي العاطفة وحدها دون فهم؟', 4);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300030004', '22222222-2222-2222-2222-222222220003', 'كيف نبني وعينا؟', '• القراءة المتدرجة لا العشوائية.\n• تنويع المصادر وعدم الاكتفاء بالصوت الواحد.\n• التأمل والنقد والسؤال.', 5);
INSERT INTO verses (id, night_id, content, sort_order) VALUES ('44444444-4444-4444-4444-444400030000', '22222222-2222-2222-2222-222222220003', '﴿قُلْ هَلْ يَسْتَوِي الَّذِينَ يَعْلَمُونَ وَالَّذِينَ لَا يَعْلَمُونَ﴾', 1);
