INSERT INTO cards (id, night_id, slug, type, title, content, status) VALUES ('77777777-7777-7777-7777-777700030001', '22222222-2222-2222-2222-222222220003', 'reflection-night-3', 'reflection', 'سؤال للتأمل', 'كم فكرة تؤمن بها اليوم… لأنك فهمتها حقًا، لا لأنك سمعتها كثيرًا؟', 'published');
