INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300040000', '22222222-2222-2222-2222-222222220004', 'ما هو الأمان العاطفي؟', '• الشعور بالقبول والطمأنينة في العلاقات.\n• الفرق بين الأمان العاطفي والاعتماد المرضي.\n• لماذا يحتاج الإنسان إلى “موضع سكن” نفسي؟', 1);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300040001', '22222222-2222-2222-2222-222222220004', 'لماذا نفقد الأمان العاطفي؟', '• تجارب الطفولة القاسية.\n• العلاقات السامة أو المهدِّدة.\n• الاعتماد المفرط على الناس بدل الله.\n• أثر السوشيال ميديا والمقارنة المستمرة.', 2);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300040002', '22222222-2222-2222-2222-222222220004', 'كيف يظهر غياب الأمان؟', '• القلق والخوف المستمر.\n• ضعف الثقة بالنفس.\n• التعلق المؤذي أو الانسحاب.\n• هشاشة مواجهة الابتلاءات.', 3);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300040003', '22222222-2222-2222-2222-222222220004', 'كربلاء: الثبات الداخلي وسط الخطر', '• كيف جسّد الحسين (ع) الطمأنينة رغم الألم؟\n• «هون ما نزل بي أنه بعين الله».\n• لماذا خاف بعض الناس… وثبت آخرون؟', 4);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300040004', '22222222-2222-2222-2222-222222220004', 'كيف نبني الأمان العاطفي؟', '• تعميق العلاقة بالله.\n• إعادة تعريف القيمة الذاتية.\n• اختيار العلاقات الآمنة.\n• بناء وعي فكري وروحي أعمق.', 5);
INSERT INTO verses (id, night_id, content, sort_order) VALUES ('44444444-4444-4444-4444-444400040000', '22222222-2222-2222-2222-222222220004', '﴿هُوَ الَّذِي أَنزَلَ السَّكِينَةَ فِي قُلُوبِ الْمُؤْمِنِينَ﴾', 1);
