INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300050000', '22222222-2222-2222-2222-222222220005', 'ما معنى السياق؟', '• لماذا لا يكفي النص وحده؟\n• أثر الزمان والمكان والظرف.\n• الفرق بين الفهم والاقتطاع.', 1);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300050001', '22222222-2222-2222-2222-222222220005', 'كيف تُشوَّه الحقيقة؟', '• الاجتزاء الإعلامي.\n• الأحكام السريعة.\n• إسقاط الماضي على الحاضر والعكس.', 2);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300050002', '22222222-2222-2222-2222-222222220005', 'الدين خارج سياقه', '• سوء فهم النصوص الدينية.\n• أسباب النزول والظروف التاريخية.\n• خطر القراءة الانتقائية.', 3);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300050003', '22222222-2222-2222-2222-222222220005', 'كربلاء: مأساة الوعي', '• كيف رأت أمةٌ الحسين بعين السلطة؟\n• هل كان الناس يجهلون الحسين… أم يجهلون السياق؟\n• أثر الإعلام والسلطة في صناعة الفهم.', 4);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300050004', '22222222-2222-2222-2222-222222220005', 'كيف نحمي وعينا؟', '• التثبت قبل الحكم.\n• فهم السياق قبل الموقف.\n• مقاومة التبسيط المخلّ.', 5);
