INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300060000', '22222222-2222-2222-2222-222222220006', 'ما معنى الإنسانية؟', '• الفرق بين الرحمة والشفقة العابرة.\n• الإنسانية كقيمة دينية لا اجتماعية فقط.\n• لماذا يصبح بعض الناس إنسانيين بشروط؟', 1);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300060001', '22222222-2222-2222-2222-222222220006', 'حين تصبح الأخلاق انتقائية', '• لماذا نحسن لمن نحب ونقسو على من نختلف معه؟\n• الازدواجية الأخلاقية.\n• اختبار الأخلاق الحقيقي وقت الخصومة.', 2);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300060002', '22222222-2222-2222-2222-222222220006', 'مدرسة أهل البيت والإنسانية', '• الإطعام رغم الحاجة.\n• الكرامة حتى مع المختلف.\n• الأخلاق قبل الانتصار.', 3);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300060003', '22222222-2222-2222-2222-222222220006', 'كربلاء: الإنسانية وسط القسوة', '• الحسين (ع) وسقي جيش الحر.\n• كيف بقيت الأخلاق حاضرة حتى مع العدو؟\n• الفرق بين الموقف الصلب والقلب القاسي.', 4);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300060004', '22222222-2222-2222-2222-222222220006', 'كيف نبني إنسانيتنا؟', '• توسيع دائرة الرحمة.\n• مقاومة القسوة اليومية.\n• مراجعة أخلاقنا وقت الغضب والاختلاف.', 5);
