INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300070000', '22222222-2222-2222-2222-222222220007', 'ما هو التعلّق؟', '• الفرق بين الحب الصحي والتعلّق المؤذي.\n• لماذا يتعلق الإنسان؟\n• التعلّق كاحتياج نفسي لا كاختيار واعٍ دائمًا.', 1);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300070001', '22222222-2222-2222-2222-222222220007', 'كيف نفقد أنفسنا داخل التعلّق؟', '• التعلق بالأشخاص.\n• التعلق بالعادات والسلوكيات.\n• التعلق بصورة الذات أو الماضي.', 2);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300070002', '22222222-2222-2222-2222-222222220007', 'لماذا نخاف الفقد؟', '• الخوف من الوحدة.\n• الفراغ الداخلي.\n• التعلق بوصفه بحثًا عن الأمان.', 3);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300070003', '22222222-2222-2222-2222-222222220007', 'كربلاء: الحرية من التعلّق', '• ماذا يعني أن يتحرر الإنسان من الدنيا؟\n• كيف قدّم الحسين (ع) المبدأ على التعلّقات؟\n• لماذا عجز بعض الناس عن نصرته رغم معرفتهم بالحقيقة؟', 4);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300070004', '22222222-2222-2222-2222-222222220007', 'كيف نحرر أنفسنا؟', '• بناء المعنى الداخلي.\n• تقوية العلاقة بالله كمصدر أمان.\n• التمييز بين الحب والتعلّق.\n• التدرج في فك الارتباط المؤذي.', 5);
