INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300090000', '22222222-2222-2222-2222-222222220009', 'لماذا يشتاق الإنسان إلى الله ويخافه في الوقت نفسه؟', '• الفطرة والبحث عن المعنى.\n• لماذا لا يهدأ القلب رغم الانشغال؟\n• الشوق إلى الله وسط ضجيج الحياة.', 1);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300090001', '22222222-2222-2222-2222-222222220009', 'لماذا نهرب من الله؟', '• لأن الله يكشف حقيقتنا.\n• الخوف من الذنب وعدم الاستحقاق.\n• وهم الاستغناء والسيطرة.', 2);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300090002', '22222222-2222-2222-2222-222222220009', 'الهروب النفسي من الألم', '• الانشغال كوسيلة للهروب.\n• اللذة والضجيج وتأجيل المواجهة.\n• لماذا نهرب من العلاج رغم حاجتنا إليه؟', 3);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300090003', '22222222-2222-2222-2222-222222220009', 'لماذا نعود دائمًا؟', '• لأن الإنسان لا يحتمل الفراغ الداخلي.\n• العلاقة بين الإيمان والمعنى النفسي.\n• “يا من لا ملجأ منه إلا إليه”.', 4);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300090004', '22222222-2222-2222-2222-222222220009', 'كربلاء: بين الهروب والعودة', '• الحرّ بن يزيد: نموذج العودة الشجاعة.\n• عمر بن سعد: حين لا تكفي المعرفة وحدها.\n• الصراع داخل النفس بين الحق والخوف.', 5);
INSERT INTO verses (id, night_id, content, sort_order) VALUES ('44444444-4444-4444-4444-444400090000', '22222222-2222-2222-2222-222222220009', '﴿فَفِرُّوا إِلَى اللَّهِ﴾', 1);
INSERT INTO verses (id, night_id, content, sort_order) VALUES ('44444444-4444-4444-4444-444400090001', '22222222-2222-2222-2222-222222220009', '﴿أَلَا بِذِكْرِ اللَّهِ تَطْمَئِنُّ الْقُلُوبُ﴾', 2);
INSERT INTO verses (id, night_id, content, sort_order) VALUES ('44444444-4444-4444-4444-444400090002', '22222222-2222-2222-2222-222222220009', '﴿بَلِ الْإِنسَانُ عَلَى نَفْسِهِ بَصِيرَةٌ﴾', 3);
INSERT INTO verses (id, night_id, content, sort_order) VALUES ('44444444-4444-4444-4444-444400090003', '22222222-2222-2222-2222-222222220009', '﴿ثُمَّ تَابَ عَلَيْهِمْ لِيَتُوبُوا﴾', 4);
