INSERT INTO cards (id, night_id, slug, type, title, content, status) VALUES ('77777777-7777-7777-7777-777700090000', '22222222-2222-2222-2222-222222220009', 'quote-night-9', 'quote', 'الإمام الحسين (ع)', 'ماذا وجد من فقدك؟ وما الذي فقد من وجدك؟', 'published');
INSERT INTO cards (id, night_id, slug, type, title, content, status) VALUES ('77777777-7777-7777-7777-777700090001', '22222222-2222-2222-2222-222222220009', 'reflection-night-9', 'reflection', 'سؤال للتأمل', 'هل ابتعادي أحيانًا عن الله… سببه عدم الإيمان، أم الخوف من مواجهة شيءٍ داخلي؟', 'published');
