INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300110000', '22222222-2222-2222-2222-222222220011', 'ما هو الكسل؟', '• الفرق بين الراحة المشروعة والكسل المذموم.\n• الكسل كحالة نفسية قبل أن يكون سلوكًا.\n• كيف تتحول الطاقات المعطلة إلى خسارة داخلية؟', 1);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300110001', '22222222-2222-2222-2222-222222220011', 'الكسل كمقبرة للذات', '• كيف يقتل الكسل الطموح؟\n• لماذا يعيش بعض الناس بلا أثر؟\n• القبر ينهي الجسد… لكن الكسل قد ينهي المعنى قبل الموت.', 2);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300110002', '22222222-2222-2222-2222-222222220011', 'كربلاء: نهضة ضد السكون', '• هل كان يمكن للحسين (ع) أن يختار الراحة؟\n• كيف واجه موجات التخويف والتخذيل؟\n• الإصلاح كحركة… لا كفكرة فقط.', 3);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300110003', '22222222-2222-2222-2222-222222220011', 'لماذا نقع في الكسل؟', '• ضعف الهدف والرسالة.\n• التسويف: “لاحقًا”.\n• التعلق بالراحة.\n• البيئة المحبطة.', 4);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300110004', '22222222-2222-2222-2222-222222220011', 'كيف نواجه الكسل؟', '• استحضار المعنى: لماذا أعيش؟\n• تقسيم الخطوات الصغيرة.\n• محاسبة النفس يوميًا.\n• الاقتداء بأهل البيت (ع) في العمل والثبات.', 5);
INSERT INTO verses (id, night_id, content, sort_order) VALUES ('44444444-4444-4444-4444-444400110000', '22222222-2222-2222-2222-222222220011', '﴿وَأَن لَّيْسَ لِلْإِنسَانِ إِلَّا مَا سَعَى﴾', 1);
INSERT INTO verses (id, night_id, content, sort_order) VALUES ('44444444-4444-4444-4444-444400110001', '22222222-2222-2222-2222-222222220011', '﴿وَقُلِ اعْمَلُوا فَسَيَرَى اللَّهُ عَمَلَكُمْ﴾', 2);
INSERT INTO verses (id, night_id, content, sort_order) VALUES ('44444444-4444-4444-4444-444400110002', '22222222-2222-2222-2222-222222220011', '﴿إِنَّ اللَّهَ لَا يُغَيِّرُ مَا بِقَوْمٍ حَتَّىٰ يُغَيِّرُوا مَا بِأَنفُسِهِمْ﴾', 3);
INSERT INTO narrations (id, night_id, content, sort_order) VALUES ('55555555-5555-5555-5555-555500110000', '22222222-2222-2222-2222-222222220011', 'الإمام علي (ع): «إياك والكسل والضجر فإنهما مفتاح كل شر».', 1);
INSERT INTO narrations (id, night_id, content, sort_order) VALUES ('55555555-5555-5555-5555-555500110001', '22222222-2222-2222-2222-222222220011', 'الإمام الحسين (ع): «إنما خرجت لطلب الإصلاح».', 2);
INSERT INTO narrations (id, night_id, content, sort_order) VALUES ('55555555-5555-5555-5555-555500110002', '22222222-2222-2222-2222-222222220011', 'الإمام زين العابدين (ع): «إن أحبكم إلى الله أحسنكم عملاً».', 3);
