INSERT INTO cards (id, night_id, slug, type, title, content, status) VALUES ('77777777-7777-7777-7777-777700110000', '22222222-2222-2222-2222-222222220011', 'quote-night-11', 'quote', 'الإمام علي بن أبي طالب (ع)', 'إيّاك والكسل والضجر فإنهما مفتاح كل شر', 'published');
INSERT INTO cards (id, night_id, slug, type, title, content, status) VALUES ('77777777-7777-7777-7777-777700110001', '22222222-2222-2222-2222-222222220011', 'reflection-night-11', 'reflection', 'سؤال للتأمل', 'ما الشيء الذي تؤجله منذ زمن… مع أنك تعرف أن تأجيله يسرق جزءًا من حياتك؟', 'published');
