INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300120000', '22222222-2222-2222-2222-222222220012', 'الوقف: أثر يمتد بعد الموت', '• الفرق بين الصدقة العابرة والوقف المستمر.\n• ماذا سيبقى من الإنسان بعد رحيله؟\n• تحويل اللحظة إلى زمن… والخير إلى أثر ممتد.', 1);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300120001', '22222222-2222-2222-2222-222222220012', 'لماذا لا يتحول الخير إلى أثر مستدام؟', '• ضعف الوعي بثقافة الوقف.\n• غياب الرؤية بعيدة المدى.\n• العاطفة غير المنظمة في توجيه العطاء.', 2);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300120002', '22222222-2222-2222-2222-222222220012', 'توسيع مفهوم الوقف', '• هل الوقف يقتصر على المسجد والمجلس؟\n• الوقف بوصفه مشروعًا إنسانيًا وحضاريًا.\n• الفرق بين فعل الخير… وصناعة الخير.', 3);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300120003', '22222222-2222-2222-2222-222222220012', 'نماذج من مدرسة أهل البيت (ع)', '• الإمام علي (ع) وإحياء الأرض والآبار.\n• الوقف بوصفه خدمة للحياة لا شكلًا دينيًا فقط.\n• الاستمرار الاجتماعي للخير.', 4);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300120004', '22222222-2222-2222-2222-222222220012', 'مجالات الوقف المغفول عنها اليوم', '• الوقف التعليمي.\n• الوقف الصحي.\n• الوقف السكني.\n• وقف تفريج الكرب.\n• وقف الوعي والمعرفة.\n• وقف الأسرة والطفولة.', 5);
INSERT INTO verses (id, night_id, content, sort_order) VALUES ('44444444-4444-4444-4444-444400120000', '22222222-2222-2222-2222-222222220012', '﴿لَن تَنَالُوا الْبِرَّ حَتَّىٰ تُنفِقُوا مِمَّا تُحِبُّونَ﴾', 1);
INSERT INTO verses (id, night_id, content, sort_order) VALUES ('44444444-4444-4444-4444-444400120001', '22222222-2222-2222-2222-222222220012', '﴿وَمَا تُقَدِّمُوا لِأَنفُسِكُم مِّنْ خَيْرٍ تَجِدُوهُ عِندَ اللَّهِ﴾', 2);
INSERT INTO verses (id, night_id, content, sort_order) VALUES ('44444444-4444-4444-4444-444400120002', '22222222-2222-2222-2222-222222220012', '﴿إِنَّا نَحْنُ نُحْيِي الْمَوْتَىٰ وَنَكْتُبُ مَا قَدَّمُوا وَآثَارَهُمْ﴾', 3);
