INSERT INTO resources (id, night_id, title, url, sort_order) VALUES ('66666666-6666-6666-6666-666600120000', '22222222-2222-2222-2222-222222220012', '[في الوقف والتنمية المجتمعية] Sustainable Philanthropy (العطاء المستدام).', '#', 1);
