INSERT INTO cards (id, night_id, slug, type, title, content, status) VALUES ('77777777-7777-7777-7777-777700120000', '22222222-2222-2222-2222-222222220012', 'quote-night-12', 'quote', 'بل: ماذا سيبقى منك بعد الرحيل؟', 'ليس السؤال: ماذا جمعت؟', 'published');
