INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300130000', '22222222-2222-2222-2222-222222220013', 'السؤال كقناع للنفس', '• لماذا يختبئ الإنسان أحيانًا خلف السؤال؟\n• حين يكون السؤال ترجمة لاحتياجٍ أو ألمٍ غير معلن.\n• الفرق بين السؤال الصادق والسؤال المتخفي.', 1);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300130001', '22222222-2222-2222-2222-222222220013', 'السؤال كتنفيس لا كطلب فهم', '• لماذا نسأل أحيانًا ونحن لا نريد جوابًا؟\n• أثر الغضب والانفعال على طريقة السؤال.\n• متى يتحول السؤال إلى مجرد تفريغ نفسي؟', 2);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300130002', '22222222-2222-2222-2222-222222220013', 'السؤال كاتهام غير مباشر', '• الأسئلة التي تحمل حكمًا مسبقًا.\n• كيف يتحول الحوار إلى دفاع وهجوم؟\n• أثر الظنون وسوء النية على العلاقات.', 3);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300130003', '22222222-2222-2222-2222-222222220013', 'فجوة الفهم في العلاقات', '• حين يُجاب السؤال… ويُهمَل المقصود.\n• لماذا يشعر الطرفان أحيانًا بأنهما غير مفهومين؟\n• أهمية الإصغاء قبل الإجابة.', 4);
INSERT INTO topics (id, night_id, title, content, sort_order) VALUES ('33333333-3333-3333-3333-333300130004', '22222222-2222-2222-2222-222222220013', 'كيف نعيد بناء السؤال؟', '• الانتقال من التلميح إلى الوضوح.\n• التعبير الصادق عن الاحتياج والمشاعر.\n• الصراحة بوصفها نضجًا لا ضعفًا.', 5);
INSERT INTO verses (id, night_id, content, sort_order) VALUES ('44444444-4444-4444-4444-444400130000', '22222222-2222-2222-2222-222222220013', '﴿يَعْلَمُ خَائِنَةَ الأَعْيُنِ وَمَا تُخْفِي الصُّدُورُ﴾', 1);
